import java.util.*;

class MovieDatabase {
    List<String> allTitles = new ArrayList<>();
    Map<String, Double> ratingByTitle = new HashMap<>();
    Map<String, List<String>> byGenre = new HashMap<>();
    Map<String, String> genreByTitle = new HashMap<>();  // needed to find genre for removal

    public void add(String title, String genre, double rating) {
        allTitles.add(title);
        ratingByTitle.put(title, rating);
        byGenre.computeIfAbsent(genre, k -> new ArrayList<>()).add(title);
        genreByTitle.put(title, genre);
    }

    public boolean remove(String title) {
        if (!ratingByTitle.containsKey(title)) return false;
        allTitles.remove(title);
        ratingByTitle.remove(title);
        String genre = genreByTitle.remove(title);
        if (genre != null) {
            List<String> genreList = byGenre.get(genre);
            if (genreList != null) genreList.remove(title);
        }
        return true;
    }
}

public class App {
    public static void main(String[] args) {
        MovieDatabase db = new MovieDatabase();
        db.add("Dune", "Sci-Fi", 8.0);
        db.add("The Matrix", "Sci-Fi", 8.7);
        db.add("Inception", "Sci-Fi", 8.8);

        System.out.println("Before: " + db.allTitles.size() + " titles, matrix rated: " + db.ratingByTitle.get("The Matrix"));
        db.remove("The Matrix");
        System.out.println("After remove: " + db.allTitles.size() + " titles");
        System.out.println("Matrix rating: " + db.ratingByTitle.get("The Matrix"));
        System.out.println("Sci-Fi count: " + db.byGenre.get("Sci-Fi").size());
    }
}

