import java.util.*;

public class App {
    public static void main(String[] args) {
        Map<String, Set<String>> studentCourses = new LinkedHashMap<>();
        studentCourses.put("Aisha",  new HashSet<>(Arrays.asList("CS101", "MATH202")));
        studentCourses.put("Carlos", new HashSet<>());  // no courses
        studentCourses.put("Priya",  new HashSet<>(Arrays.asList("ENG301")));

        List<String> removed = new ArrayList<>();
        Iterator<Map.Entry<String, Set<String>>> it = studentCourses.entrySet().iterator();
        while (it.hasNext()) {
            Map.Entry<String, Set<String>> entry = it.next();
            if (entry.getValue().isEmpty()) {
                removed.add(entry.getKey());
                it.remove();
            }
        }

        System.out.println("Removed inactive: " + removed);
        System.out.println("Active students: " + studentCourses.size());
    }
}

