import java.util.*;

class Flight {
    String id, origin, destination;
    double price;
    Flight(String id, String origin, String dest, double price) {
        this.id=id; this.origin=origin; this.destination=dest; this.price=price;
    }
    public String toString() { return id + " " + origin + " to " + destination + " ₹" + price; }
}

class FlightBookingSystem {
    Map<String, Flight>            byId         = new HashMap<>();
    Map<String, List<Flight>>      byDest       = new HashMap<>();
    TreeMap<Double, List<Flight>>  byPrice      = new TreeMap<>();
    Set<String>                    cancelled    = new HashSet<>();
    Map<String, List<String>>      passengers   = new HashMap<>();

    void addFlight(Flight f) {
        byId.put(f.id, f);
        byDest.computeIfAbsent(f.destination, k -> new ArrayList<>()).add(f);
        byPrice.computeIfAbsent(f.price, k -> new ArrayList<>()).add(f);
        passengers.put(f.id, new ArrayList<>());
    }

    boolean book(String flightId, String name) {
        if (cancelled.contains(flightId)) return false;
        List<String> pax = passengers.get(flightId);
        if (pax == null) return false;
        pax.add(name);
        return true;
    }

    void cancel(String flightId) { cancelled.add(flightId); }

    double cheapestTo(String dest) {
        List<Flight> flights = byDest.getOrDefault(dest, Collections.emptyList());
        if (flights.isEmpty()) return -1;
        return Collections.min(flights, Comparator.comparingDouble(f -> f.price)).price;
    }

    List<String> passengersOn(String flightId) {
        return Collections.unmodifiableList(
            passengers.getOrDefault(flightId, Collections.emptyList()));
    }
}

public class App {
    public static void main(String[] args) {
        FlightBookingSystem sys = new FlightBookingSystem();
        sys.addFlight(new Flight("HYD-001", "HYD", "Delhi", 3500.0));
        sys.addFlight(new Flight("HYD-002", "HYD", "Delhi", 4200.0));
        sys.addFlight(new Flight("HYD-003", "HYD", "Mumbai", 2800.0));

        sys.book("HYD-001", "Aisha");
        sys.book("HYD-001", "Raj");
        sys.cancel("HYD-002");

        System.out.println("HYD-001 found: " + sys.byId.get("HYD-001"));
        System.out.println("Passengers on HYD-001: " + sys.passengersOn("HYD-001"));
        System.out.println("Cheapest to Delhi: ₹" + sys.cheapestTo("Delhi"));
        System.out.println("HYD-002 cancelled: " + sys.cancelled.contains("HYD-002"));
    }
}

import java.util.*;

class Deal {
    String name, stage;
    double value;
    Deal(String name, double value, String stage) {
        this.name=name; this.value=value; this.stage=stage;
    }
    public String toString() { return name + "(₹" + value + ")"; }
}

class SalesPipeline {
    List<Deal> deals = new ArrayList<>();
    Set<String> closedNames = new HashSet<>();
    Map<String, Double> closedValues = new HashMap<>();

    void add(Deal d) { deals.add(d); }

    List<String> closeStagedDeals() {
        List<String> closed = new ArrayList<>();
        Iterator<Deal> it = deals.iterator();
        while (it.hasNext()) {
            Deal d = it.next();
            if ("QUALIFIED".equals(d.stage)) {
                closed.add(d.name);
                closedNames.add(d.name);
                closedValues.put(d.name, d.value);
                it.remove();
            }
        }
        return closed;
    }

    List<Deal> topDeals(int n) {
        List<Deal> copy = new ArrayList<>(deals);
        copy.sort((a, b) -> Double.compare(b.value, a.value));
        return copy.subList(0, Math.min(n, copy.size()));
    }

    double totalClosedValue() {
        double total = 0;
        for (double v : closedValues.values()) total += v;
        return total;
    }

    Map<String, Integer> stageStats() {
        Map<String, Integer> stats = new HashMap<>();
        for (Deal d : deals) stats.put(d.stage, stats.getOrDefault(d.stage, 0) + 1);
        return stats;
    }
}

public class App {
    public static void main(String[] args) {
        SalesPipeline pipeline = new SalesPipeline();
        pipeline.add(new Deal("Startup A", 320000, "LEAD"));
        pipeline.add(new Deal("Enterprise Deal", 1200000, "QUALIFIED"));
        pipeline.add(new Deal("Series B", 850000, "QUALIFIED"));

        // Close only QUALIFIED deals — Series B stays (we add it back as LEAD)
        pipeline.deals.remove(2);  // remove Series B first
        pipeline.add(new Deal("Series B", 850000, "LEAD"));  // re-add as LEAD

        List<String> closed = pipeline.closeStagedDeals();
        System.out.println("Closed deals: " + closed);
        System.out.println("Top 2 open: " + pipeline.topDeals(2));
        System.out.println("Closed value: ₹" + pipeline.totalClosedValue());

        Map<String, Integer> stats = pipeline.stageStats();
        List<String> sortedStages = new ArrayList<>(stats.keySet());
        Collections.sort(sortedStages);
        Map<String, Integer> sortedStats = new LinkedHashMap<>();
        for (String s : sortedStages) sortedStats.put(s, stats.get(s));
        System.out.println("Stage counts: " + sortedStats);
    }
}

import java.util.*;

class Book {
    String isbn, title, genre;
    int year;
    Book(String isbn, String title, String genre, int year) {
        this.isbn=isbn; this.title=title; this.genre=genre; this.year=year;
    }
    public String toString() { return title + " (" + year + ")"; }
}

class Library2 {
    List<Book>                      catalog      = new ArrayList<>();
    Map<String, Book>               byIsbn       = new HashMap<>();
    Map<String, TreeSet<String>>    byGenre      = new HashMap<>();
    Set<String>                     checkedOut   = new HashSet<>();
    TreeMap<String, Book>           byTitle      = new TreeMap<>();

    void add(Book b) {
        catalog.add(b);
        byIsbn.put(b.isbn, b);
        byGenre.computeIfAbsent(b.genre, k -> new TreeSet<>()).add(b.title);
        byTitle.put(b.title, b);
    }

    boolean checkout(String isbn) {
        if (!byIsbn.containsKey(isbn) || checkedOut.contains(isbn)) return false;
        checkedOut.add(isbn);
        return true;
    }

    void returnBook(String isbn) { checkedOut.remove(isbn); }

    boolean isAvailable(String isbn) {
        return byIsbn.containsKey(isbn) && !checkedOut.contains(isbn);
    }

    List<String> purgeOldEditions(int beforeYear) {
        List<String> log = new ArrayList<>();
        Iterator<Book> it = catalog.iterator();
        while (it.hasNext()) {
            Book b = it.next();
            if (b.year < beforeYear) {
                log.add(b.toString());
                it.remove();
                byIsbn.remove(b.isbn);
                byTitle.remove(b.title);
                Set<String> g = byGenre.get(b.genre);
                if (g != null) g.remove(b.title);
                checkedOut.remove(b.isbn);
            }
        }
        return log;
    }

    List<String> titlesBetween(String from, String to) {
        return new ArrayList<>(byTitle.subMap(from, true, to, true).keySet());
    }
}

public class App {
    public static void main(String[] args) {
        Library2 lib = new Library2();
        lib.add(new Book("ISBN-001", "Dune",         "SciFi", 1965));
        lib.add(new Book("ISBN-002", "Foundation",   "SciFi", 1951));
        lib.add(new Book("ISBN-003", "Clean Code",   "Tech",  2008));
        lib.add(new Book("ISBN-004", "Effective Java","Tech", 2018));

        System.out.println("ISBN-003 checked out: " + lib.checkout("ISBN-003"));
        System.out.println("ISBN-003 available: "   + lib.isAvailable("ISBN-003"));

        List<String> purged = lib.purgeOldEditions(2010);
        System.out.println("Purged: " + purged);

        System.out.println("Titles A-E: " + lib.titlesBetween("A", "E"));
        System.out.println("SciFi (sorted): " + lib.byGenre.get("SciFi"));
    }
}

import java.util.*;

class Employee {
    String name, dept;
    double salary;
    Employee(String n, String d, double s) { name=n; dept=d; salary=s; }
    public String toString() { return name + "(" + salary + ")"; }
}

public class App {
    static List<Employee> highEarners(List<Employee> list, double threshold) {
        List<Employee> result = new ArrayList<>();
        for (Employee e : list) if (e.salary > threshold) result.add(e);
        result.sort((a, b) -> Double.compare(b.salary, a.salary));
        return Collections.unmodifiableList(result);
    }

    static Map<String, Double> deptSalaryMap(List<Employee> list) {
        Map<String, Double> sumMap = new HashMap<>();
        Map<String, Integer> cntMap = new HashMap<>();
        for (Employee e : list) {
            sumMap.put(e.dept, sumMap.getOrDefault(e.dept, 0.0) + e.salary);
            cntMap.put(e.dept, cntMap.getOrDefault(e.dept, 0) + 1);
        }
        Map<String, Double> avg = new HashMap<>();
        for (String dept : sumMap.keySet()) {
            avg.put(dept, sumMap.get(dept) / cntMap.get(dept));
        }
        return avg;
    }

    static List<Employee> shuffleAndPick(List<Employee> list, int n) {
        List<Employee> copy = new ArrayList<>(list);
        Collections.shuffle(copy);
        return copy.subList(0, Math.min(n, copy.size()));
    }

    public static void main(String[] args) {
        List<Employee> employees = Arrays.asList(
            new Employee("Aisha",  "Engineering", 95000),
            new Employee("Raj",    "Sales",        72000),
            new Employee("Priya",  "Engineering",  88000),
            new Employee("Vikram", "Sales",         68000)
        );

        System.out.println("High earners: " + highEarners(employees, 80000));
        System.out.println("Engineering avg: " + deptSalaryMap(employees).get("Engineering"));
        System.out.println("Picked 2 (count): " + shuffleAndPick(employees, 2).size());
    }
}

import java.util.*;

class Task {
    String id, title;
    int priority;  // 1-5
    Task(String id, String title, int priority) {
        this.id=id; this.title=title; this.priority=priority;
    }
    public String toString() { return title; }
}

class TaskManager {
    List<Task>                 allTasks    = new ArrayList<>();
    Map<String, Task>          byId        = new HashMap<>();
    Map<String, List<Task>>    byAssignee  = new HashMap<>();
    Set<String>                completed   = new HashSet<>();
    TreeMap<Integer, List<Task>> byPriority = new TreeMap<>(Collections.reverseOrder());

    void assign(Task t, String assignee) {
        allTasks.add(t);
        byId.put(t.id, t);
        byAssignee.computeIfAbsent(assignee, k -> new ArrayList<>()).add(t);
        byPriority.computeIfAbsent(t.priority, k -> new ArrayList<>()).add(t);
    }

    void complete(String taskId) {
        completed.add(taskId);
        Iterator<Task> it = allTasks.iterator();
        while (it.hasNext()) {
            if (it.next().id.equals(taskId)) { it.remove(); break; }
        }
    }

    List<Task> pendingFor(String assignee) {
        List<Task> all = byAssignee.getOrDefault(assignee, Collections.emptyList());
        List<Task> pending = new ArrayList<>();
        for (Task t : all) if (!completed.contains(t.id)) pending.add(t);
        return pending;
    }

    List<Task> highPriorityTasks() {
        List<Task> result = new ArrayList<>();
        for (List<Task> tasks : byPriority.values()) result.addAll(tasks);
        return result;
    }
}

public class App {
    public static void main(String[] args) {
        TaskManager tm = new TaskManager();
        Task t1 = new Task("T001", "Fix Bug",    5);
        Task t2 = new Task("T002", "Add Feature", 3);
        Task t3 = new Task("T003", "Write Docs",  2);

        tm.assign(t1, "Aisha");
        tm.assign(t2, "Aisha");
        tm.assign(t3, "Raj");

        System.out.println("Total tasks: " + tm.allTasks.size());
        System.out.println("Pending for Aisha: " + tm.pendingFor("Aisha"));
        System.out.println("High priority (5): " + tm.byPriority.get(5));

        tm.complete("T003");
        System.out.println("Completed: " + tm.completed.contains("T003"));
    }
}
